from datetime import timedelta
from functools import wraps

from flask import Flask, session, redirect, url_for, request, render_template_string, g

app = Flask(__name__)
app.secret_key = 'change-this-secret-key'
app.permanent_session_lifetime = timedelta(days=7)

# Simple in-memory user store
USER_DB = {
    'admin': 'password',
    'user': '1234'
}

def login_required(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if not session.get('user_id'):
            return redirect(url_for('login', next=request.path))
        return f(*args, **kwargs)
    return wrapper

@app.before_request
def load_logged_in_user():
    g.user = session.get('user_id')

@app.route('/')
def index():
    if g.user:
        return render_template_string('''
            <p>Hello, {{ user }}! You are logged in.</p>
            <p><a href="{{ url_for('protected') }}">Protected area</a></p>
            <p><a href="{{ url_for('logout') }}">Logout</a></p>
        ''', user=g.user)
    return render_template_string('''
        <p>You are not logged in.</p>
        <p><a href="{{ url_for('login') }}">Login here</a></p>
    ''')

@app.route('/login', methods=['GET', 'POST'])
def login():
    error = None
    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        if USER_DB.get(username) == password:
            session.permanent = True
            session['user_id'] = username
            return redirect(request.args.get('next') or url_for('index'))
        error = 'Invalid username or password'
    return render_template_string('''
        {% if error %}<p style="color:red;">{{ error }}</p>{% endif %}
        <form method="post">
            <p><input name="username" placeholder="Username"></p>
            <p><input name="password" type="password" placeholder="Password"></p>
            <p><button type="submit">Login</button></p>
        </form>
    ''', error=error)

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/protected')
@login_required
def protected():
    return render_template_string('''
        <h1>Secret Page for {{ user }}</h1>
        <p><a href="{{ url_for('logout') }}">Logout</a></p>
    ''', user=g.user)

if __name__ == '__main__':
    app.run(debug=True)